mapper.delete:
/* PV발전량 삭제 */
DELETE FROM tb_pv_gen 
 WHERE pv_gen_idx = #{pvGenIdx}

mapper.select:
/* PV발전량 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_pv_gen
 WHERE pv_gen_idx = #{pvGenIdx}

/* PV발전량 상세조회ByUnique */
SELECT pv_gen_idx,
       site_id,
       device_id,
       std_date,
       gen_val,
       temp,
       reg_date,
       mod_date
  FROM tb_pv_gen
 WHERE site_id = #{siteId}
   AND device_id = #{deviceId}
   AND std_date = #{stdDate}

/* PV발전량 목록조회 */
SELECT site_id,
       std_date,
       SUM(gen_val) gen_val
  FROM tb_pv_gen
 WHERE site_id = #{siteId}
   AND std_date BETWEEN #{beginDate} AND #{endDate}
 GROUP BY site_id, std_date
